// // This module implements a 2-to-1 multiplexer with an enable input.
// When EN is high, the output Y should be equal to input B. When EN is low, the output Y should be equal to input A.
module mux_2to1_enable(
  input [7:0] A,
  input [7:0] B,
  input EN,
  output reg [7:0] Y
);

  always @ (A, B, EN) begin
    if(EN) begin
      Y <= A;
    end
    else begin
      Y <= B;
    end
  end

endmodule
